import{_ as e,o as t,c as i,ag as r}from"./chunks/framework.D2Ob5GRY.js";const p=JSON.parse('{"title":"套餐与授权","description":"","frontmatter":{},"headers":[],"relativePath":"intro/plans-and-licensing.md","filePath":"intro/plans-and-licensing.md"}'),l={name:"intro/plans-and-licensing.md"};function n(o,a,s,h,d,c){return t(),i("div",null,[...a[0]||(a[0]=[r('<h1 id="套餐与授权" tabindex="-1">套餐与授权 <a class="header-anchor" href="#套餐与授权" aria-label="Permalink to &quot;套餐与授权&quot;">​</a></h1><blockquote><p>了解 LinScio AI 的套餐类型、授权费与年维护费、宽限期及机器绑定说明。</p></blockquote><h2 id="前提条件" tabindex="-1">前提条件 <a class="header-anchor" href="#前提条件" aria-label="Permalink to &quot;前提条件&quot;">​</a></h2><ul><li>已阅读 <a href="/docs/intro/what-is-linscio.html">什么是 LinScio AI</a>。</li></ul><h2 id="三个套餐对比-个人版-团队版-机构版" tabindex="-1">三个套餐对比（个人版 / 团队版 / 机构版） <a class="header-anchor" href="#三个套餐对比-个人版-团队版-机构版" aria-label="Permalink to &quot;三个套餐对比（个人版 / 团队版 / 机构版）&quot;">​</a></h2><p>（此处为占位：方案中 2.1 节内容，可根据实际套餐在管理后台配置后填写。）</p><h2 id="一次性授权费-vs-年维护费" tabindex="-1">一次性授权费 vs 年维护费 <a class="header-anchor" href="#一次性授权费-vs-年维护费" aria-label="Permalink to &quot;一次性授权费 vs 年维护费&quot;">​</a></h2><ul><li><strong>一次性买断</strong>：支付买断费后，获得该软件授权关系，授权码/账号即代表已买断。</li><li><strong>年维护费</strong>：买断后须每年支付年维护费才能维持软件使用权；未支付则无法继续使用。系统中用「有效期至」或「维护截止日」表示当前维护期。</li></ul><h2 id="宽限期说明" tabindex="-1">宽限期说明 <a class="header-anchor" href="#宽限期说明" aria-label="Permalink to &quot;宽限期说明&quot;">​</a></h2><ul><li>账号路径：维护期到期后通常有约 30 天宽限期，宽限内仍可换 token 但会看到续费提醒；超过宽限期后无法获取新令牌。</li><li>授权码路径：当前为到期即限制，无宽限期；若需宽限期可在门户侧按「expires_at + N 天」策略配置。</li></ul><h2 id="机器绑定数量限制说明" tabindex="-1">机器绑定数量限制说明 <a class="header-anchor" href="#机器绑定数量限制说明" aria-label="Permalink to &quot;机器绑定数量限制说明&quot;">​</a></h2><p>不同套餐对应不同的机器绑定数量上限；在用户中心可查看已绑定机器列表，迁移服务器时需解绑旧机器再在新机器上激活。</p><h2 id="如何升级套餐" tabindex="-1">如何升级套餐 <a class="header-anchor" href="#如何升级套餐" aria-label="Permalink to &quot;如何升级套餐&quot;">​</a></h2><p>请联系管理员或在管理后台办理套餐升级与延期。</p><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><ul><li><a href="/docs/intro/system-requirements.html">系统要求</a></li><li><a href="/docs/quickstart/register-and-buy.html">注册与购买</a></li></ul>',16)])])}const m=e(l,[["render",n]]);export{p as __pageData,m as default};
